def solve(age, sex, surgery_type, major_surgery, chf, sepsis, pneumonia, immobilizing_cast, hip_pelvis_leg_fracture, stroke, multiple_trauma, acute_spinal_cord_injury, varicose_veins, swollen_legs, central_venous_access, history_dvt_pe, family_thrombosis, factor_v_leiden, prothrombin_20210a, elevated_homocysteine, lupus_anticoagulant, anticardiolipin_antibody, heparin_thrombocytopenia, mobility_status, inflammatory_bowel_disease, bmi_ge_25, acute_mi, copd, malignancy):
    # Step 1: age_score_evaluation
    # Evaluate points for age criterion based on age ranges
    if age <= 40:
        age_score = 0
    elif age <= 60:
        age_score = 1
    elif age <= 74:
        age_score = 2
    else:
        age_score = 3
    yield {
        "step_name": "age_score_evaluation",
        "step_description": "Evaluate the points for age criterion based on the patient's age",
        "step_result": age_score,
        "unit": None
    }

    # Step 2: sex_score_evaluation
    # Determine points for sex criterion
    sex_score = 0 if sex == "Male" else 1 if sex == "Female" else 0
    yield {
        "step_name": "sex_score_evaluation",
        "step_description": "Determine the points for sex criterion",
        "step_result": sex_score,
        "unit": None
    }

    # Step 3: surgery_score_evaluation
    # Determine points for type of surgery criterion based on predefined mapping
    surgery_mapping = {
        "None": 0,
        "Minor": 1,
        "Major >45 min laparoscopic/arthroscopic": 2,
        "Elective major lower extremity arthroplasty": 5
    }
    surgery_score = surgery_mapping.get(surgery_type, 0)
    yield {
        "step_name": "surgery_score_evaluation",
        "step_description": "Determine the points for type of surgery criterion",
        "step_result": surgery_score,
        "unit": None
    }

    # Step 4: recent_event_score_evaluation
    # Sum points for recent (≤1 month) events, each true condition adds its respective points
    recent_event_score = 0
    if major_surgery:
        recent_event_score += 1
    if chf:
        recent_event_score += 1
    if sepsis:
        recent_event_score += 1
    if pneumonia:
        recent_event_score += 1
    if immobilizing_cast:
        recent_event_score += 1
    if hip_pelvis_leg_fracture:
        recent_event_score += 5
    if stroke:
        recent_event_score += 5
    if multiple_trauma:
        recent_event_score += 5
    if acute_spinal_cord_injury:
        recent_event_score += 5
    yield {
        "step_name": "recent_event_score_evaluation",
        "step_description": "Calculate the points for recent (≤1 month) events",
        "step_result": recent_event_score,
        "unit": None
    }

    # Step 5: venous_disease_clotting_score_evaluation
    # Sum points for venous disease or clotting disorder criteria, each true condition adds its respective points
    venous_clotting_score = 0
    if varicose_veins:
        venous_clotting_score += 1
    if swollen_legs:
        venous_clotting_score += 1
    if central_venous_access:
        venous_clotting_score += 2
    if history_dvt_pe:
        venous_clotting_score += 3
    if family_thrombosis:
        venous_clotting_score += 3
    if factor_v_leiden:
        venous_clotting_score += 3
    if prothrombin_20210a:
        venous_clotting_score += 3
    if elevated_homocysteine:
        venous_clotting_score += 3
    if lupus_anticoagulant:
        venous_clotting_score += 3
    if anticardiolipin_antibody:
        venous_clotting_score += 3
    if heparin_thrombocytopenia:
        venous_clotting_score += 3
    yield {
        "step_name": "venous_disease_clotting_score_evaluation",
        "step_description": "Calculate the points for venous disease or clotting disorder criteria",
        "step_result": venous_clotting_score,
        "unit": None
    }

    # Step 6: mobility_score_evaluation
    # Determine points for mobility criterion based on predefined mapping
    mobility_mapping = {
        "Normal, out of bed": 0,
        "Medical patient currently on bed rest": 1,
        "Patient confined to bed >72 hours": 2
    }
    mobility_score = mobility_mapping.get(mobility_status, 0)
    yield {
        "step_name": "mobility_score_evaluation",
        "step_description": "Determine the points for mobility criterion",
        "step_result": mobility_score,
        "unit": None
    }

    # Step 7: other_history_score_evaluation
    # Sum points for other present and past history criteria, each true condition adds its respective points
    other_history_score = 0
    if inflammatory_bowel_disease:
        other_history_score += 1
    if bmi_ge_25:
        other_history_score += 1
    if acute_mi:
        other_history_score += 1
    if copd:
        other_history_score += 1
    if malignancy:
        other_history_score += 2
    yield {
        "step_name": "other_history_score_evaluation",
        "step_description": "Calculate the points for other present and past history criteria",
        "step_result": other_history_score,
        "unit": None
    }

    # Step 8: total_caprini_score_calculation
    # Sum all individual criterion scores to get the total Caprini Score
    total_caprini_score = age_score + sex_score + surgery_score + recent_event_score + venous_clotting_score + mobility_score + other_history_score
    yield {
        "step_name": "total_caprini_score_calculation",
        "step_description": "Sum all individual criterion scores to get the total Caprini Score",
        "step_result": total_caprini_score,
        "unit": None
    }

    return total_caprini_score
